.error-summary {
    @apply fixed z-10 inset-0 overflow-y-auto;
    outline-none focus:outline-none transition duration-100 ease-in-out
}
.error-summary::before {
    @apply fixed inset-0 bg-gray-900/75 transition duration-300 ease-in-out
}
.error-summary-dialog {
    @apply relative mx-auto my-6 max-w-md bg-white rounded-2xl shadow-md;
    padding: 6px;
    transform: scale(1.02)
}

