html: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta http-equiv="X-UA-Compatible" content="IE=edge">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Error Summary</title>
    <script src="https://cdn.tailwindcss.com"></script>
</head>
<body>

    <!-- The error summary will be displayed here -->
    <div class="error-summary fixed z-10 inset-0 overflow-y-auto">
        <div class="error-summary::before fixed inset-0 bg-gray-900/75 transition duration-300 ease-in-out"></div>
        <div class="error-summary-dialog relative mx-auto my-6 max-w-md bg-white rounded-2xl shadow-md">
            <h2 class="text-lg font-bold mb-4">Validation Errors</h2>
            <ul>
                <li>Username is required</li>
                <li>Password is required</li>
            </ul>
        </div>
    </div>

    <!-- Import the JavaScript file that will handle the error summary -->
    <script src="error-summary.js"></script>
</body>
</html>
javascript: document.addEventListener('DOMContentLoaded', function() {
    const errorSummary = document.querySelector('.error-summary');

    // Check if there are any errors to display
    if (localStorage.getItem("errors") !== null) {
        const errors = JSON.parse(localStorage.getItem("errors"));
        const errorSummaryDialog = document.querySelector('.error-summary-dialog');

        // Display the error summary
        errorSummaryDialog.innerHTML += '<h2>Validation Errors</h2>';
        errors.forEach(error => {
            const errorListItem = document.createElement("li");
            errorListItem.textContent = error;
            errorSummaryDialog.appendChild(errorListItem);
        });
        errorSummaryDialog.style.transform = "scale(1)";
        errorSummary.style.opacity = 1;
    }

    // Add event listener to close the error summary
    const closeButton = document.querySelector(".close-button");
    closeButton.addEventListener("click", function() {
        errorSummary.style.opacity = 0;
        setTimeout(function() {
            errorSummary.style.display = "none";
        }, 100);
    });
});
